interface ComparisonIntroProps {
  className?: string
}

export default function ComparisonIntro({ className = '' }: ComparisonIntroProps) {
  const sectionRef = useRef(null)
  const headingRef = useRef(null)
  const textRef = useRef(null)
  const underlineRef = useRef(null)
  const paragraphRefs = useRef<(HTMLParagraphElement | null)[]>([])

  useEffect(() => {
    const ctx = gsap.context(() => {
      // Heading animation
      gsap.from(headingRef.current, {
        y: 30,
        opacity: 0,
        duration: 1,
        scrollTrigger: {
          trigger: sectionRef.current,
          start: 'top 80%',
        },
      })

      // Paragraphs stagger animation
      gsap.from(paragraphRefs.current, {
        y: 20,
        opacity: 0,
        duration: 0.8,
        stagger: 0.15,
        delay: 0.3,
        scrollTrigger: {
          trigger: sectionRef.current,
          start: 'top 80%',
        },
      })

      // Underline animation - scale and rotate
      gsap.from(underlineRef.current, {
        scale: 0,
        rotation: -5,
        opacity: 0,
        duration: 0.8,
        delay: 0.5,
        ease: "power2.out",
        clearProps: "transform,opacity",
        scrollTrigger: {
          trigger: sectionRef.current,
          start: 'top 80%',
        },
      })
    })

    return () => ctx.revert()
  }, [])

  return (
    <section
      ref={sectionRef}
      className={`${sora.className} py-8 bg-white ${className}`}
    >
      <div className="mx-auto px-4 md:px-8">
        <div className="bg-[#ceff00] text-[#001109] relative overflow-hidden rounded-[32px]">
          {/* Bottom left decorative image */}
          <div className="absolute left-0 bottom-0 pointer-events-none z-0">
            <Image
              src={bottomLeftImage}
              alt=""
              width={693}
              height={746}
              className="opacity-80"
              priority
            />
          </div>

          {/* Top right decorative image */}
          <div className="absolute right-0 top-0 pointer-events-none z-0">
            <Image
              src={topRightImage}
              alt=""
              width={400}
              height={400}
              className="opacity-70"
              priority
            />
          </div>

          {/* Content */}
          <div className="relative z-10 py-20 px-6 md:py-24 md:px-8 lg:py-32 lg:px-[280px]">
            <div className="max-w-4xl mx-auto">
              {/* Heading with underline */}
              <div className="mb-12 md:mb-16">
                <h2
                  ref={headingRef}
                  className="font-bold text-[40px] md:text-[55px] leading-[1.2] text-center tracking-[0.55px]"
                >
                  The biggest difference is
                  <br />
                  our{' '}
                  <span className="relative inline-block">
                    insider knowledge
                    {/* Animated underline */}
                    <div
                      ref={underlineRef}
                      className="absolute -bottom-6 md:-bottom-8 left-[10%] md:left-[-5%] w-[80%] md:w-[110%] h-[20px] md:h-[35px] pointer-events-none rotate-[2.735deg]"
                    >
                      <UnderlineSVG />
                    </div>
                  </span>
                </h2>
              </div>

              {/* Body text */}
              <div className="space-y-6 text-[#001109] max-w-3xl mx-auto mt-12 md:mt-16">
                <p
                  ref={el => {if (el) paragraphRefs.current[0] = el}}
                  className="text-[16px] md:text-[18px] leading-[1.5] text-left"
                >
                  There are a lot of good paid ad agencies out there. But if you were happy with one of them, you wouldn&apos;t be here.
                </p>

                <p
                  ref={el => {if (el) paragraphRefs.current[1] = el}}
                  className="text-[16px] md:text-[18px] leading-[1.5] text-left"
                >
                  Before starting Profit Mill, we spent years managing ads in-house for Google. That meant working with thousands of advertisers across industries, budgets, and growth stages. This helped us understand what actually works, what consistently fails, and how success is really measured from inside the platform.
                </p>

                <p
                  ref={el => {if (el) paragraphRefs.current[2] = el}}
                  className="text-[16px] md:text-[18px] leading-[1.5] text-left"
                >
                  We also partnered with hundreds of paid ad agencies. We saw the good, the bad, and the ones that looked busy but didn&apos;t actually deliver results. So we built Profit Mill by taking the best practices, leaving the wasted effort, and applying a repeatable framework that drives measurable profit.
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  )
}